function getOptimizedImageUrl(url, width, quality = 80) {
  // Supposons que url est de la forme https://res.cloudinary.com/.../upload/v123456/product.jpg
  const parts = url.split('/upload/');
  const transformations = `w_${width},q_${quality},f_auto`;
  return `${parts[0]}/upload/${transformations}/${parts[1]}`;
}
// Exemple : getOptimizedImageUrl(product.image, 640) -> .../upload/w_640,q_80,f_auto/product.jpg
```

