function OptimizedPicture({ src, alt, className, webpSrc }) {
  // webpSrc = src remplacé par l'extension .webp
  return (
    <picture className={className}>
      <source srcSet={webpSrc} type="image/webp" />
      <img src={src} alt={alt} loading="lazy" />
    </picture>
  );
}
